La fonction ci-dessous permet d’effectuer une recherche par dichotomie de l’index m de l’élément x dans un
tableau L de valeurs distinctes et triées.
def dicho(x,L):
    g = 0
    d = len(L)-1
    while g <= d:
        m = (g+d)//2
        if L[m] == x:
            return m
        elif L[m] < x:
            g = m+1
        else:
            d = m-1
    return None
